const body = $input.first().json.body || $input.first().json;

const required = ['business_name', 'niche', 'suburb'];
const missing = required.filter(f => !body[f] || String(body[f]).trim() === '');

if (missing.length > 0) {
  throw new Error('Missing required fields: ' + missing.join(', '));
}

const allowedNiches = [
  'electrician', 'plumber', 'builder', 'painter', 'landscaper',
  'physio', 'chiro', 'osteo', 'dentist', 'gp',
  'beauty', 'skin-clinic', 'hair-salon', 'nail-salon',
  'personal-trainer', 'yoga', 'pilates',
  'accountant', 'solicitor', 'mortgage-broker',
  'cafe', 'restaurant', 'food-truck',
  'other'
];

const niche = String(body.niche).toLowerCase().trim();
if (!allowedNiches.includes(niche)) {
  throw new Error('Invalid niche: ' + niche);
}

// Sanitise inputs
const businessName = String(body.business_name).trim().substring(0, 120);
const suburb = String(body.suburb).trim().substring(0, 80);
const phone = body.phone ? String(body.phone).trim().substring(0, 20) : null;
const cfToken = body.cf_turnstile_token || null;

// UTM passthrough
const utm = {
  utm_source: body.utm_source || null,
  utm_medium: body.utm_medium || null,
  utm_campaign: body.utm_campaign || null,
  utm_content: body.utm_content || null,
  referrer_url: body.referrer_url || null
};

return [{
  json: {
    business_name: businessName,
    niche,
    suburb,
    phone,
    cf_turnstile_token: cfToken,
    ...utm
  }
}];

const row = Array.isArray($input.first().json) ? $input.first().json[0] : $input.first().json;
const leadId = row.lead_id;

if (!leadId) {
  throw new Error('Supabase did not return lead_id. Check Prefer: return=representation header.');
}

return [{ json: { lead_id: leadId, ...row } }];
